let telefone = '';
const whatsapp = $node["Webhook"].json["body"]["Whatsapp Convidado"] || '';
telefone = whatsapp;

// Extrair o DDI a partir do telefone limpo
const ddi = telefone.slice(0, 2);

// Verificar se o DDI é igual a 55
if (ddi === '55') {
  const ddd = telefone.slice(2, 4);
  if (Number(ddd) > 28) {
    telefone = '55' + telefone.slice(2, 4) + telefone.slice(-8).replace(/\s/g, '');
  } else {
    telefone = '55' + telefone.slice(2, 4) + telefone.slice(-9).replace(/\s/g, '');
  }
} else {
  telefone = telefone.replace(/[(\)\+\s-]/g, ''); // Tratar como número internacional
}

const result = {
    whatsapp: telefone,
};

// Retorno no formato esperado pelo n8n
return [{ json: result }];

